// Get all existing pubDates from the sheet
const sheetItems = $('Fetch Sheet Rows').all();
const existingDates = new Set(
  sheetItems
    .map(item => item.json.pubDate)
    .filter(Boolean)
);

// Get all RSS items from previous node
const rssItems = items;

// Sort by pubDate (latest first)
const sortedItems = rssItems.sort((a, b) => {
  return new Date(b.json.pubDate) - new Date(a.json.pubDate);
});

// Find first non-duplicate
for (const item of sortedItems) {
  if (!existingDates.has(item.json.pubDate)) {
    return [item];
  }
}

return [];

