=<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0"/>

  <link href="https://fonts.googleapis.com/css2?family=Poppins:wght@400;600;800&display=swap" rel="stylesheet">

  <style>
    * {
      margin: 0;
      padding: 0;
      box-sizing: border-box;
      font-family: 'Poppins', sans-serif;
    }

    body {
      width: 100%;
      height: 100vh;
      display: flex;
      align-items: center;
      justify-content: center;
      background: #000;
    }

    .screen {
      width: 360px;
      height: 640px;
      border-radius: 32px;
      overflow: hidden;
      position: relative;
      background: linear-gradient(160deg, #0f2027, #203a43, #2c5364);
      box-shadow: 0 20px 60px rgba(0,0,0,0.6);
      padding: 24px;
      display: flex;
      flex-direction: column;
      justify-content: space-between;
    }

    .top {
      display: flex;
      justify-content: space-between;
      align-items: center;
      font-size: 14px;
      opacity: 0.9;
    }

    .badge {
      padding: 6px 12px;
      font-size: 11px;
      font-weight: 600;
      border-radius: 999px;
      background: linear-gradient(90deg, #ff416c, #ff4b2b);
      color: #fff;
    }

    .live {
      display: flex;
      align-items: center;
      gap: 6px;
      font-weight: 600;
      font-size: 12px;
      color: #fff;
    }

    .dot {
      width: 8px;
      height: 8px;
      background: #ff3b30;
      border-radius: 50%;
      box-shadow: 0 0 8px rgba(255, 59, 48, 0.8);
    }

    .content {
      margin-top: 40px;
      flex-grow: 1;
      display: flex;
      align-items: center;
    }

    .title {
      font-size: 28px;
      font-weight: 800;
      line-height: 1.4;
      color: #fff;
    }

    .bottom {
      font-size: 13px;
      opacity: 0.7;
    }

    .brand {
      margin-top: 6px;
      font-size: 15px;
      font-weight: 600;
      color: #ffffff;
    }

    .glow {
      position: absolute;
      width: 200px;
      height: 200px;
      background: radial-gradient(circle, rgba(255,255,255,0.15), transparent);
      top: -50px;
      right: -50px;
    }
  </style>
</head>

<body>
  <div class="screen">

    <div class="glow"></div>

    <div class="top">
      <div class="badge">BREAKING</div>

      <div class="live">
        <div class="dot"></div>
        LIVE
      </div>
    </div>

    <div class="content">
      <div class="title">
        {title}
      </div>
    </div>

    <div class="bottom">
      Powered by your news engine ⚡
      <div class="brand">YourBrand</div>
    </div>

  </div>
</body>
</html>
